Query.Sql:
with ug as ( select distinct Record ->> '$.LinkagePatientId.NhsNumber.@extension' as NhsNumber,
unnest ([[Record ->> '$.Treatment.Surgery.ProcedureOpcs.@code'], Record ->> '$.Treatment[*].Surgery.ProcedureOpcs[*].@code'], recursive := true) as ProcedureOpcs,
unnest ([[Record ->> '$.Treatment.Surgery.ProcedureDate'], Record ->> '$.Treatment[*].Surgery.ProcedureDate'], recursive := true) as ProcedureDate from omop_staging.cosd_staging_901 where type = 'UG' ) select distinct NhsNumber, ProcedureOpcs, ProcedureDate from ug where NhsNumber is not null and ProcedureOpcs is not null;
